def max_sum_numbers_with_equal_sum_of_digits(nums):
    digit_sum_to_max = {}
    ans = -1

    for num in nums:
        sum_of_digits = sum(map(int, str(num)))

        prev_max = digit_sum_to_max.get(sum_of_digits, 0)
        if prev_max:
            ans = max(ans, num + prev_max)

        digit_sum_to_max[sum_of_digits] = max(num, prev_max)

    return ans
```

