        const prevMax = digitSumToMax[sumOfDigits] || 0;
        if (prevMax) {
            ans = Math.max(ans, num + prevMax);
        }
        digitSumToMax[sumOfDigits] = Math.max(num, prevMax);
    }

    return ans;
}
