public int maxSumNumbersWithEqualSumOfDigits(int[] nums) {
    HashMap<Integer, Integer> digitSumToMax = new HashMap<>();
    int ans = -1;

    for (int num : nums) {
        int sumOfDigits = 0;
        for (int temp = num; temp != 0; temp /= 10) {
            sumOfDigits += temp % 10;
        }

        int prevMax = digitSumToMax.getOrDefault(sumOfDigits, 0);
        if (prevMax != 0) {
            ans = Math.max(ans, num + prevMax);
        }
        digitSumToMax.put(sumOfDigits, Math.max(num, prevMax));
    }

    return ans;
}
```

